VALUES
  ('diplomatic-0248a032-moex-00186', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '半總統制國家依總統或總理所掌握之行政權大小又分為總理－總統制及總統－總理制；請問下列何者 為半總統制國家？', '["印度", "俄羅斯", "瑞典", "新加坡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00187', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '關於冷戰時期同屬社會主義陣營的中共與前蘇聯之改革開放經驗，下列敘述何者正確？', '["中共的改革有其時序，先政後經，但仍維持共產黨一黨專政的地位", "前蘇聯的改革是以一套長期的政策來建立市場經濟，以達宏觀經濟穩定", "兩國的改革開放皆面臨因經濟與生產工具由國家轉移到私人手中所致的貪污", "前蘇聯的改革模式為「漸進模式」，中共為「震盪療法」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00188', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '印度人民黨（BJP）自2014年以來連續贏得三次國會下議院大選（2014、2019、2024年），莫迪（Narendra Mosi）也於2024年6月之後展開其第三任任期。關於印度政黨與民主政治，下列敘述何者錯誤？', '["印度人民黨成立於1984年，為一印度教民族主義政黨，以宗教信仰為其主要的政治動員基礎", "印度人民黨本身開始受到全國性的注意，是在該黨關於應該如何處置那些在奧圖曼帝國侵略後於原 本印度教寺廟所在地興建的清真寺之相關言論", "印度人民黨執政之後所帶來的重要意涵，為該黨試圖轉化印度獨立之初所建立的世俗性政治與法律 制度", "印度人民黨已經和許多商業團體發展不錯的關係，它的意識型態重點為「印度性」，而非經濟孤立 主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00189', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '中共經濟快速發展並成為世界主要強權之一後，外界所關注的重要問題是中共是否會如現代化理論論 點一樣走向自由民主。關於中共改革開放以來的政治發展，下列敘述何者錯誤？', '["1989年的天安門事件是中共建政之後所遭遇的統治正當性嚴重危機", "1989年之後中共權力結構的進一步鞏固，確認了「新威權主義」的復甦", "中共在地方層級引進多黨競爭性選舉，被視為政治民主化的鼓勵性指標", "中共威權統治下出色的經濟表現，是支持共產政權統治正當性的關鍵因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00190', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '伊朗於2024年7月選出新總統，由改革派的心臟外科醫生佩澤什基安（MassoudPezeshkian）當選。關 於伊朗的政治制度與發展，下列敘述何者正確？', '["伊朗的現代化發展過程中，有三個截然不同但息息相關的時期：巴勒維王朝早期（1921-1941年）與 晚期（1941-1979年）以及伊斯蘭共和國（1979年迄今）", "二次大戰之後，英國主導伊朗進行的大規模政治改革，包括廢除君主制、修改其憲法及改變社會行 為者之間的權力關係", "巴勒維政府於1963年發動紅色革命，旨在對抗外國勢力對伊朗國內政治與經濟社會的干涉", "1979年宗教領袖何梅尼帶領的革命不僅廢除伊朗的君主制，更建立一個奉行世俗主義的現代國家"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00191', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '2024年6月的南非大選結果標示著非洲民族議會（ANC）獨大的時代告終，對該國民主政治的運作帶 來一定的影響。關於南非的民主政治制度，下列敘述何者錯誤？', '["南非的憲法具最高權威，且規定總統享有任命權與決策權", "為處理種族隔離制度的遺緒，南非於1995年成立「事實與調解委員會」落實轉型正義", "南非的國會屬於兩院制，包括國民大會（NationalAssembly）與省級國家議會（NationalCouncilof Provinces）", "南非總統由人民直選產生並組成政府，面臨不信任投票時必須解散國會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00192', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '民意調查是了解並且預測選舉結果的重要手段，不過，「全國性」的民意調查在美國總統大選當中， 可能不見得反映最後的選舉結果，其最主要的原因來自：', '["民意調查工具不準確，測不到真實民意", "美國民眾的拒訪率太高，往往抽不到足夠的樣本來推估民意", "間接選舉的制度設計，候選人在各州贏者全拿「選舉人團票」，選舉結果往往會由關鍵的幾個搖擺 州決定", "美國政治人物往往拒絕承認民調結果，把「抵制民調」當成一種動員的工具，所以民調測不準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00193', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '下列關於法國總統選舉制度及其效應的敘述何者錯誤？', '["該制為需要絕對多數的單一選舉，政黨支持具高度重要性", "若無人在第一輪投票中獲絕對多數有效票則舉行第二輪投票", "第一輪投票之所有候選人參與第二輪投票，獲絕對多數票者當選", "第二輪的投票往往鼓勵意識型態相近的政黨組成選舉聯盟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00194', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '關於法國總統大選與國會議員的選舉，下列何者錯誤？', '["國會議員與總統大選皆採用兩輪決選制。若第一輪沒有人贏得絕對多數，則取前兩名進入第二輪決選", "在兩輪決選制的情形下，讓各黨缺乏在一開始就合作的動機，所以會使得小黨林立", "在第二輪進行的時候，往往會有很多聯盟的出現，此時選民傾向於避免讓最不喜歡的那位候選人當 選，因此會有很多策略投票（棄保）的情形", "兩輪決選制容易出現多黨聯盟，這個現象最有名的解釋理論來自杜瓦傑法則（Duverger''slaw）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL),
  ('diplomatic-0248a032-moex-00195', 'diplomatic-0248a032', 'diplomatic-0248a032-moex-113-c655adf3', 'sub-diplomatic-0248a032-04', NULL, 'single_choice', '英國在2024年進行大選，關於英國的憲政體制，下列何者錯誤？', '["國會選舉的時間是由首相決定的，但每一屆的任期最長不能超過5年", "國會選舉制度是全部採取單一選區相對多數決制，此制度的特色是刻意扭曲選票和席次的比例性， 讓選票集中在大黨以盡量避免聯合內閣的出現", "在大部分的時候，首相會選在民調最有利的時候解散國會，進行全面改選", "國會分成上議院和下議院，上議院由貴族組成，權力和下議院一樣大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:55+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-國際法組"}'::jsonb, NULL)
